    <script>
        const svg = d3.select("#spiral");
        const width = 800;
        const height = 800;
        const centerX = width / 2;
        const centerY = height / 2;

        const g = svg.append("g")
            .attr("transform", "translate(" + centerX + ", " + centerY + ")");

        // Draw multiple spirals to represent weaving
        const numStrands = 8;
        const colors = ["#00ff88", "#00cc88", "#009988", "#006688", 
                       "#ff00ff", "#cc00ff", "#9900ff", "#ffff00"];

        for (let s = 0; s < numStrands; s++) {
            const points = [];
            const offset = (s / numStrands) * Math.PI * 2;

            for (let i = 0; i <= 56; i++) {
                const angle = i * 0.4 + offset * (i / 56);
                const radius = 20 + i * 6;
                points.push({
                    x: Math.cos(angle) * radius,
                    y: Math.sin(angle) * radius,
                    depth: i
                });
            }

            const line = d3.line()
                .x(d => d.x)
                .y(d => d.y)
                .curve(d3.curveCardinal);

            g.append("path")
                .datum(points)
                .attr("fill", "none")
                .attr("stroke", colors[s])
                .attr("stroke-width", s === 7 ? 3 : 1.5)
                .attr("opacity", s === 7 ? 1 : 0.4)
                .attr("d", line);
        }

        // Draw the synthesis point
        const angle56 = 56 * 0.4;
        const radius56 = 20 + 56 * 6;
        const x56 = Math.cos(angle56) * radius56;
        const y56 = Math.sin(angle56) * radius56;

        g.append("circle")
            .attr("cx", x56)
            .attr("cy", y56)
            .attr("r", 12)
            .attr("fill", "#ff00ff")
            .attr("stroke", "#ffff00")
            .attr("stroke-width", 3);

        // Add milestone labels
        const milestones = [0, 11, 22, 33, 44, 55, 56];
        milestones.forEach(m => {
            const a = m * 0.4;
            const r = 20 + m * 6;
            const x = Math.cos(a) * r;
            const y = Math.sin(a) * r;

            g.append("text")
                .attr("x", x * 1.12)
                .attr("y", y * 1.12)
                .attr("text-anchor", "middle")
                .attr("dominant-baseline", "middle")
                .attr("fill", m === 56 ? "#ff00ff" : "#00ff88")
                .attr("font-size", m === 56 ? "16px" : "11px")
                .attr("font-weight", m === 56 ? "bold" : "normal")
                .text(m === 0 ? "GENESIS" : m === 56 ? "D56: SYNTHESIS" : "D" + m);
        });

        // Draw connecting lines representing woven fabric
        const weavePoints = [];
        for (let i = 55; i <= 56; i+= 0.5) {
            const a = i * 0.4;
            const r = 20 + i * 6;
            weavePoints.push({
                x: Math.cos(a) * r,
                y: Math.sin(a) * r,
                r: r
            });
        }

        weavePoints.forEach((p, i) => {
            if (i < weavePoints.length - 1) {
                for (let s = 0; s < 6; s++) {
                    g.append("line")
                        .attr("x1", p.x + Math.cos(s) * 5)
                        .attr("y1", p.y + Math.sin(s) * 5)
                        .attr("x2", weavePoints[i+1].x + Math.cos(s + 1) * 5)
                        .attr("y2", weavePoints[i+1].y + Math.sin(s + 1) * 5)
                        .attr("stroke", "#00ff88")
                        .attr("stroke-width", 0.5)
                        .attr("opacity", 0.3);
                }
            }
        });
    </script>
